#define LIMIT -999

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

int maximum_cl( int a, int b, int c){
    int k;
    if( a <= b )
        k = b;
    else 
        k = a;

    if( k <= c )
        return c;
    else
        return k;
}

__attribute__((reqd_work_group_size(BLOCK_SIZE, 1, 1)))
__kernel void nw_kernel1(
    __global int* referrence,
    __global int* input_itemsets,
    __global int* output_itemsets,
    __local int* input_itemsets_l,
    __local int* reference_l,
    int max_cols,
    int penalty,
    int blk,
    int block_width,
    int worksize,
    int offset_r,
    int offset_c)
{
    int b_index_x = get_global_id(0) / BLOCK_SIZE;
    int b_index_y = blk - 1 - b_index_x;

    if (b_index_x >= blk) return;

    int local_id = get_local_id(0);

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int idx = i * BLOCK_SIZE + j;
            int global_row = b_index_y * BLOCK_SIZE + i + 1;
            int global_col = b_index_x * BLOCK_SIZE + j + 1;
            reference_l[idx] = referrence[max_cols * global_row + global_col];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            int idx = i * (BLOCK_SIZE + 1) + j;
            int global_row = b_index_y * BLOCK_SIZE + i;
            int global_col = b_index_x * BLOCK_SIZE + j;
            input_itemsets_l[idx] = input_itemsets[max_cols * global_row + global_col];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            int diag = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1];
            int left = input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty;
            int up = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum_cl(diag, left, up);
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int idx = (i + 1) * (BLOCK_SIZE + 1) + j + 1;
            int global_row = b_index_y * BLOCK_SIZE + i + 1;
            int global_col = b_index_x * BLOCK_SIZE + j + 1;
            input_itemsets[max_cols * global_row + global_col] = input_itemsets_l[idx];
        }
    }
}

